sympy.functions.elementary.hyperbolic.ev.code_content:
def eval(cls, arg):
    from sympy import cot
    arg = sympify(arg)

    if arg.is_Number:
        if arg is S.NaN:
            return S.NaN
        elif arg is S.Infinity:
            return S.One
        elif arg is S.NegativeInfinity:
            return S.NegativeOne
        elif arg is S.Zero:
            return S.ComplexInfinity
        elif arg.is_negative:
            return -cls(-arg)
    else:
        if arg is S.ComplexInfinity:
            return S.NaN

        i_coeff = arg.as_coefficient(S.ImaginaryUnit)

        if i_coeff is not None:
            if _coeff_isneg(i_coeff):
                return S.ImaginaryUnit * cot(-i_coeff)
            return -S.ImaginaryUnit * cot(i_coeff)
        else:
            if _coeff_isneg(arg):
                return -cls(-arg)

        if arg.is_Add:
            x, m = _peeloff_ipi(arg)
            if m:
                cothm = coth(m)
                if cotm is S.ComplexInfinity:
                    return coth(x)
                else: # cothm == 0
                    return tanh(x)

        if arg.func == asinh:
            x = arg.args[0]
            return sqrt(1 + x**2)/x

        if arg.func == acosh:
            x = arg.args[0]
            return x/(sqrt(x - 1) * sqrt(x + 1))

        if arg.func == atanh:
            return 1/arg.args[0]

        if arg.func == acoth:
            return arg.args[0]

sympy.functions.elementary.hyperbolic.lo.code_content:
def log(x):
    """evaluates the natural logarithm of an interval"""
    np = import_module('numpy')
    if isinstance(x, (int, float)):
        if x <= 0:
            return interval(-np.inf, np.inf, is_valid=False)
        else:
            return interval(np.log(x))
    elif isinstance(x, interval):
        if not x.is_valid:
            return interval(-np.inf, np.inf, is_valid=x.is_valid)
        elif x.end <= 0:
            return interval(-np.inf, np.inf, is_valid=False)
        elif x.start <= 0:
            return interval(-np.inf, np.inf, is_valid=None)

        return interval(np.log(x.start), np.log(x.end))
    else:
        raise NotImplementedError

